/**
 * Base64url codec for the practice deep link
 * (`/practice?deck=<base64url>`). The encoding is part of the cross-game
 * contract so a link generated by the Lorcana deployable's deck builder can
 * be opened by any partner client and decoded with this same helper.
 *
 * The deck-text *contents* remain game-specific and are validated by each
 * deployable's `validateDeckText`.
 *
 * Encoding:
 *   utf-8 → base64 → replace `+`→`-`, `/`→`_`, strip trailing `=`.
 */

function utf8ToBase64(text: string): string {
  if (typeof Buffer !== "undefined") {
    return Buffer.from(text, "utf-8").toString("base64");
  }
  // Browser fallback. `btoa` only handles latin-1, so encode utf-8 bytes
  // through a binary string first.
  const bytes = new TextEncoder().encode(text);
  let binary = "";
  for (const b of bytes) binary += String.fromCharCode(b);
  return btoa(binary);
}

function base64ToUtf8(b64: string): string {
  if (typeof Buffer !== "undefined") {
    return Buffer.from(b64, "base64").toString("utf-8");
  }
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new TextDecoder().decode(bytes);
}

export function encodeDeckToUrlParam(deckText: string): string {
  return utf8ToBase64(deckText).replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

/**
 * Returns null for any input that isn't a non-empty base64url string —
 * `null`, `undefined`, empty, or characters outside `[A-Za-z0-9_-]`. Never
 * throws; callers route a null result to a "deck-error" page state. The
 * widened parameter type lets the page layer feed
 * `URLSearchParams.get("deck")` (which is `string | null`) directly.
 */
export function decodeDeckFromUrlParam(value: string | null | undefined): string | null {
  if (typeof value !== "string" || value.length === 0) return null;
  if (!/^[A-Za-z0-9_-]+$/.test(value)) return null;
  const padded =
    value.replace(/-/g, "+").replace(/_/g, "/") + "=".repeat((4 - (value.length % 4)) % 4);
  try {
    return base64ToUtf8(padded);
  } catch {
    return null;
  }
}
